CREATE TABLE `party_hall_bookings` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user id` int NOT NULL,
  `customer name` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `customer_phone` varchar(25) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `event date` date NOT NULL,
  `start time` time NOT NULL,
  `end time` time NOT NULL,
  `person_count` int NOT NULL,
  `snacks count` int NOT NULL DEFAULT '0',
  `water_count` int NOT NULL DEFAULT '0',
  `cake count` int NOT NULL DEFAULT '0',
  `add_ons_json` json DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `base_charge` decimal(10,2) NOT NULL,
  `add_on_charge` decimal(10,2) NOT NULL,
  `total_charge` decimal(10,2) NOT NULL,
  `status` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'BOOKED',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_partyhall_user` (`user id`),
  KEY `idx_partyhall_date` (`event date`)
